import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../models/user_model.dart'; import '../../../../services/api_service.dart'; final adminRequestProvider = StateNotifierProvider<AdminRequestNotifier, AdminRequestState>((ref)=>AdminRequestNotifier(ref)); class AdminRequestState { final List<PendingUser> pending; final List<PasswordResetRequest> resets; final bool loading; AdminRequestState({this.pending=const[], this.resets=const[], this.loading=false}); AdminRequestState copyWith({List<PendingUser>? pending, List<PasswordResetRequest>? resets, bool? loading}) => AdminRequestState(pending: pending??this.pending, resets: resets??this.resets, loading: loading??this.loading); } class AdminRequestNotifier extends StateNotifier<AdminRequestState> { final Ref ref; AdminRequestNotifier(this.ref) : super(AdminRequestState()); Future<void> load() async { state = state.copyWith(loading:true); final api = ref.read(apiServiceProvider); final p = await api.getPendingUsers(); final r = await api.getPasswordResetRequests(); state = state.copyWith(pending: p.map((e)=>PendingUser.fromJson(e)).toList(), resets: r.map((e)=>PasswordResetRequest.fromJson(e)).toList(), loading:false); } Future<void> approve(String id, String phone, String name, String role) async { final api = ref.read(apiServiceProvider); await api.updatePendingUserStatus(id, 'approved'); await api.createUserAccount(phone: phone, fullName: name, role: role, password: '123456'); load(); } Future<void> reject(String id, String reason) async { final api = ref.read(apiServiceProvider); await api.updatePendingUserStatus(id, 'rejected', rejectReason: reason); load(); } }
